    """LRU Cache dengan kapasitas tetap."""
    def __init__(self, maxsize={{maxsize}}):
        from collections import OrderedDict
        self.maxsize = maxsize
        self._data = OrderedDict()

    def get(self, key, default=None):
        if key in self._data:
            self._data.move_to_end(key)
            return self._data[key]
        return default

    def put(self, key, value):
        if key in self._data:
            self._data.move_to_end(key)
        self._data[key] = value
        if len(self._data) > self.maxsize:
            self._data.popitem(last=False)

    def __getitem__(self, key):
        return self.get(key)

    def __setitem__(self, key, value):
        self.put(key, value)

    def __contains__(self, key):
        return key in self._data

    def __len__(self):
        return len(self._data)

class {{nama_class}}:
    """TTL Cache sederhana."""
    def __init__(self, ttl_seconds={{ttl}}):
        self.ttl = ttl_seconds
        self._data = {}
        self._times = {}

    def _is_expired(self, key):
        import time
        return time.time() - self._times.get(key, 0) > self.ttl

    def get(self, key, default=None):
        import time
        if key in self._data and not self._is_expired(key):
            return self._data[key]
        self._data.pop(key, None)
        self._times.pop(key, None)
        return default

    def put(self, key, value):
        import time
        self._data[key] = value
        self._times[key] = time.time()

    def purge(self):
        for k in list(self._data.keys()):
            if self._is_expired(k):
                self._data.pop(k, None)
                self._times.pop(k, None)

    def __len__(self):
        self.purge()
        return len(self._data)

