class {{nama_class}}:
    """Counter yang preserve insertion order."""
    def __init__(self, iterable=None):
        from collections import OrderedDict
        self._data = OrderedDict()
        if iterable:
            for item in iterable:
                self._data[item] = self._data.get(item, 0) + 1

    def inc(self, key, n=1):
        self._data[key] = self._data.get(key, 0) + n

    def most_common(self, n=None):
        items = sorted(self._data.items(), key=lambda kv: kv[1], reverse=True)
        return items[:n] if n else items

    def __getitem__(self, key):
        return self._data.get(key, 0)

    def items(self):
        return self._data.items()

class {{nama_class}}:
    """Bidirectional dict."""
    def __init__(self, initial=None):
        self.forward = {}
        self.backward = {}
        if initial:
            for k, v in initial.items():
                self.set(k, v)

    def set(self, key, value):
        if key in self.forward:
            old_v = self.forward[key]
            self.backward.pop(old_v, None)
        if value in self.backward:
            old_k = self.backward[value]
            self.forward.pop(old_k, None)
        self.forward[key] = value
        self.backward[value] = key

    def get_key(self, value, default=None):
        return self.backward.get(value, default)

    def get_value(self, key, default=None):
        return self.forward.get(key, default)

    def __len__(self):
        return len(self.forward)

