class {{nama_class}}:
    """Priority queue berbasis heapq."""
    def __init__(self):
        import heapq
        self._heap = []
        self._counter = 0

    def push(self, item, priority=0):
        import heapq
        heapq.heappush(self._heap, (priority, self._counter, item))
        self._counter += 1

    def pop(self):
        import heapq
        if not self._heap:
            raise IndexError("pop from empty queue")
        return heapq.heappop(self._heap)[2]

    def peek(self):
        if not self._heap:
            return None
        return self._heap[0][2]

    def __len__(self):
        return len(self._heap)

    def __bool__(self):
        return bool(self._heap)

class {{nama_class}}:
    """Ring buffer ukuran tetap."""
    def __init__(self, capacity={{capacity}}):
        self.capacity = capacity
        self._buf = [None] * capacity
        self._start = 0
        self._size = 0

    def append(self, item):
        idx = (self._start + self._size) % self.capacity
        if self._size == self.capacity:
            self._start = (self._start + 1) % self.capacity
            idx = (self._start + self._size - 1) % self.capacity
        else:
            self._size += 1
        self._buf[idx] = item

    def get_all(self):
        return [self._buf[(self._start + i) % self.capacity] for i in range(self._size)]

    def __len__(self):
        return self._size

    def clear(self):
        self._start = 0
        self._size = 0
